  @{
    var sublist_Col = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [AutoID],[Col]FROM  [Part_Operation_Serialization_Array_Index_Col]");
    var sublist_MasterID = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [AutoID],[MasterID]FROM  [Part_Operation_Serialization_Array_Index_MasterID]");
    var sublist_Row = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [AutoID],[Row]FROM  [Part_Operation_Serialization_Array_Index_Row]");
    var sublist_ToIndex = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [AutoID],[ToIndex]FROM  [Part_Operation_Serialization_Array_Index_ToIndex]");
    var sublist_PositionID = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [AutoID],[PositionID]FROM  [Part_Operation_Serialization_Array_Index_PositionID]");
  }
  @Html.AjaxGrid(Url.Action("GetSubActivateScannerArrayList", "PartNumber", new { id = Model.PartID }))
  <div class="uk-grid">
    <div class="uk-width-1-3@m">
      <div class="input-group mb-3">
        @Html.Label("Row", new { @class = "m-0 fs-14" })
        @Html.DropDownList("Row", (IEnumerable<SelectListItem>)sublist_Row, new { @class = "md-input", id = "ddlRow" })
      </div>
    </div>
    <div class="uk-width-1-3@m">
      <div class="input-group mb-3">
        @Html.Label("Col", new { @class = "m-0 fs-14" })
        @Html.DropDownList("Col", (IEnumerable<SelectListItem>)sublist_Col, new { @class = "md-input", id = "ddlCol" })
      </div>
    </div>
    <div class="uk-width-1-3@m">
      <div class="input-group mb-3">
        @Html.Label("Index", new { @class = "m-0 fs-14" })
        @Html.DropDownList("ToIndex", (IEnumerable<SelectListItem>)sublist_ToIndex, new { @class = "md-input", id = "ddlToIndex" })
      </div>
    </div>
    <div class="uk-width-1-3@m">
      <div class="input-group mb-3">
        @Html.Label("Scanner", new { @class = "m-0 fs-14" })
        @Html.DropDownList("MasterID", (IEnumerable<SelectListItem>)sublist_MasterID, new { @class = "md-input", id = "ddlMasterID" })
      </div>
    </div>
    <div class="uk-width-1-3@m">
      <div class="input-group mb-3">
        @Html.Label("Position", new { @class = "m-0 fs-14" })
        @Html.DropDownList("PositionID", (IEnumerable<SelectListItem>)sublist_PositionID, new { @class = "md-input", id = "ddlPositionID" })
      </div>
    </div>

    <div class="input-group mb-3">
      <div class="col-2 ">
        <div class="p-0 input-group mb-3 mn-r-10">
          <input id="btnUpdateActivateScannerArray" type="button" value="Add" class="md-btn md-btn-primary md-btn-small" />
        </div>
      </div>
    </div>
  </div>
  <script type="text/javascript" nonce="@Html.ScriptNonce()">
    $('#btnUpdateActivateScannerArray').click(function (e) {
      e.preventDefault(); // <------------------ stop default behaviour of button
      var v_Row = $("#ddlRow").find("option:selected").text();;
      var v_partid = $("#txtPartID").val();
      var v_Col = $("#ddlCol").find("option:selected").text();;
      var v_MasterID = $("#ddlMasterID").find("option:selected").text();;
      var v_PositionID = $("#ddlPositionID").find("option:selected").text();;
      var v_ToIndex = $("#ddlToIndex").find("option:selected").text();;

      var req = { PartID: v_partid, Row: v_Row, Col: v_Col, MasterID: v_MasterID, PositionID: v_PositionID, ToIndex: v_ToIndex };

      $.ajax({
        type: "POST",
        url: "/Engineering/PartNumber/AddActivateScannerArrayList",
        async: false,
        contentType: "application/json; charset=utf-8",
        data: JSON.stringify(req),
        success: function () {
          // Reload Grid
          updateActivateScannerArray();
        }
      })
    });

    function updateActivateScannerArray() {
      var grid = new MvcGrid(document.querySelector('#mvcActivateScannerArrayList'));
      grid.requestType = 'post';
      grid.reload();
    };

    $(document).on('click', '#mvcActivateScannerArrayList>table>tbody>tr>td>a.DeleteActivateScannerArrayList', function (e) {
      e.preventDefault(); // <------------------ stop default behaviour of button
      var target = $(this).attr("href");

      $.ajax({
        type: "POST",
        url: target,
        async: false,
        contentType: "application/json; charset=utf-8",
        success: function () {
          // Reload Grid
          updateActivateScannerArray();
        }
      })
    });
  </script>
</li>
