          <script type="text/javascript" nonce="@Html.ScriptNonce()">
            function FillStations() {
              var AreaID = $('#ddlareaid').val();
              var req2 = { AreaID: AreaID };
              $.ajax({
                type: "POST",
                url: "/Manage/Areas/FillStations",
                async: false,
                contentType: "application/json; charset=utf-8",
                data: JSON.stringify(req2),
                success: function (response) {
                  //console.log(response);
                  $("#ddlsubstation").html("");
                  $.each(response, function (index, value) {
                    $("#ddlsubstation").append(
                      $('<option></option>').val(value.Value).html(value.Text));
                  });
                },
                error: function () {
                  $("#ddlsubstation").html("");
                  $("#ddlsubstation").append(
                    $('<option></option>').val(0).html("NA"));
                }
              });
            }
          </script>
