            </div>
          </div>
          <div class="col-3">
            <div class="p-0 input-group mb-3 mn-r-10">
              @Html.Label("File:", new { @class = "m-0 fs-14" })
              @Html.TextBox("File", null, new { @class = "md-input", id = "txtfileparameters", type = "file" })
            </div>
          </div>

