          <script type="text/javascript" nonce="@Html.ScriptNonce()">

            $(document).ready(function () {
              FillStations4()
            });

            function FillStations4() {
              var AreaID = $('#ddlareaid_assembly').val();
              var req2 = { AreaID: AreaID };
              $.ajax({
                type: "POST",
                url: "/Manage/Areas/FillProcessesAssemblyInstructions",
                async: false,
                contentType: "application/json; charset=utf-8",
                data: JSON.stringify(req2),
                success: function (response) {
                  $("#ddlsubstation_assembly").html("");
                  $.each(response, function (index, value) {
                    $("#ddlsubstation_assembly").append(
                      $('<option></option>').val(value.Value).html(value.Text));
                  });
                },
                error: function () {
                  $("#ddlsubstation_assembly").html("");
                  $("#ddlsubstation_assembly").append(
                    $('<option></option>').val(0).html("NA"));
                }
              });
            }
          </script>
          <script type="text/javascript" nonce="@Html.ScriptNonce()">
          $('#btnUpdateassembly').click(function (e) {
            e.preventDefault(); // <------------------ stop default behaviour of button
              // Load new data
            var v_areaid = $("#ddlareaid_assembly").val();
            var v_substation = $("#ddlsubstation_assembly").val();
            var v_partid = $("#txtPartID").val();
            var v_comments = $("#txtComments_assembly").val();
            var v_Link = $("#txtLink_assembly").val();
            var v_ParametersSide = $("#ddlside_assembly").val();
            var v_DocType = $("#ddlDocType").val();

            if (!$("#txtLink_assembly").val()) {
              v_Link = "na";
            }

            var nurl = "";

            const fi = document.getElementById('txtfileassembly');

            if (fi.files.length > 0) {
                for (var i = 0; i <= fi.files.length - 1; i++) {
                  const fsize = fi.files.item(i).size;
                  const file = Math.round((fsize / 1024));
                  // The size of the file.
                  if (file >= 154096) {
                    alert(
                      "File too Big, please select a file less than 100mb");
                    $("#txtfileassembly").html("");
                  }
                }

                var fileUpload = $("#txtfileassembly").get(0);
                var files = fileUpload.files;

                var fileData = new FormData();

                // Looping over all files and add it to FormData object
                for (var i = 0; i < files.length; i++) {
                  fileData.append(files[i].name, files[i]);
                }
                //// Adding one more key to FormData object
                //fileData.append('username', ‘Manas’);

                v_nomber = @Model.PartID + '_' + v_ParametersSide + '_' + v_substation + '_' + @today.ToString("yyMMdd");

                fileData.append("Names", v_nomber);

                //var req2 = { v_AutoID: v_AutoID, nombre: v_nomber };

                $.ajax({
                  type: "POST",
                  url: "/Engineering/PartNumber/UploadAssemblyInstruction",
                  async: false,
                  data: fileData,
                  contentType: false,
                  processData: false,
                  success: function (response) {
                    nurl = response;
                  },
                  error: function () {

                  }
                });
              }

            var req = { PartID: v_partid, Side: v_ParametersSide, AreaID: v_areaid, ProcessID: v_substation, UrlWeb: v_Link, Url: nurl, Comments: v_comments, DocType: v_DocType };

              $.ajax({
                type: "POST",
                url: "/Engineering/PartNumber/AddAssemblyInstructions",
                async: false,
                contentType: "application/json; charset=utf-8",
                data: JSON.stringify(req),
                success: function () {
                  alert("Done!");

                  // Reload Grid
                  updateAssemblyInstruction();
                }
              })
            });

            function updateAssemblyInstruction() {
              var grid = new MvcGrid(document.querySelector('#mvcAssemblyInstructions'));
              grid.requestType = 'post';
              grid.reload();
            };

          $(document).on('click', '#mvcAssemblyInstructions>table>tbody>tr>td>a.delRowAssemblyInstructions', function (e) {
              e.preventDefault(); // <------------------ stop default behaviour of button
              var target = $(this).attr("href");

              $.ajax({
                type: "POST",
                url: target,
                async: false,
                contentType: "application/json; charset=utf-8",
                success: function () {
                  // Reload Grid
                  updateAssemblyInstruction();
                }
              })
            });

          </script>
        </div>
        @Html.AjaxGrid(Url.Action("GetAssemblyInstruction", "PartNumber", new { id = Model.PartID }))

      </li>
