                  </div>
                </div>
              </div>

              contador++;
              if (contador % ColMax == 0)
              {
                // Add a line break after each fourth item
                <div class="uk-width-1-1">
                  <hr class="uk-divider-icon" />
                </div>
              }
            }
          }
