<script type="text/javascript" nonce="@Html.ScriptNonce()">
  var scannerArrayData = [];
  var currentScanIndex = 1;

  // Generate the grid based on Rows and Cols inputs
  $('#btnGenerateScannerGrid').click(function (e) {
    e.preventDefault();

    var rows = parseInt($("#ddlRows").val());
    var cols = parseInt($("#ddlCols").val());

    if (isNaN(rows) || isNaN(cols) || rows < 1 || cols < 1) {
      alert("Please enter valid Rows and Cols values first (above in the Activate Scanner section).");
      return;
    }

    if (rows > 20 || cols > 20) {
      if (!confirm("Grid size is large (" + rows + "x" + cols + "). Continue?")) {
        return;
      }
    }

    // Reset data
    scannerArrayData = [];
    currentScanIndex = 1;
    $("#currentIndex").text(currentScanIndex);

    // Build grid HTML
    var gridHtml = '<table class="scanner-array-grid"><thead><tr><th></th>';

    // Column headers
    for (var c = 1; c <= cols; c++) {
      gridHtml += '<th>Col ' + c + '</th>';
    }
    gridHtml += '</tr></thead><tbody>';

    // Rows
    for (var r = 1; r <= rows; r++) {
      gridHtml += '<tr><th>Row ' + r + '</th>';
      for (var c = 1; c <= cols; c++) {
        gridHtml += '<td data-row="' + r + '" data-col="' + c + '" data-index="0"></td>';
      }
      gridHtml += '</tr>';
    }

    gridHtml += '</tbody></table>';

    $('#scannerArrayContainer').html(gridHtml);
    $('#scannerArrayStatus').show();
    $('#btnClearScannerPath').show();
    $('#btnSaveScannerArray').show();
  });

  // Handle cell clicks
  $(document).on('click', '.scanner-array-grid td', function (e) {
    var $cell = $(this);
    var currentIndex = parseInt($cell.attr('data-index'));

    // Double-click or click already selected cell to remove
    if (currentIndex > 0) {
      var removedIndex = currentIndex;

      // Remove from data array
      scannerArrayData = scannerArrayData.filter(function(item) {
        return item.index !== removedIndex;
      });

      // Update all cells with higher index
      $('.scanner-array-grid td').each(function() {
        var idx = parseInt($(this).attr('data-index'));
        if (idx > removedIndex) {
          $(this).attr('data-index', idx - 1);
          $(this).text(idx - 1);

          // Update in data array
          var row = parseInt($(this).attr('data-row'));
          var col = parseInt($(this).attr('data-col'));
          scannerArrayData.forEach(function(item) {
            if (item.row === row && item.col === col) {
              item.index = idx - 1;
            }
          });
        }
      });

      // Clear this cell
      $cell.removeClass('selected');
      $cell.attr('data-index', '0');
      $cell.text('');

      // Update counter
      currentScanIndex--;
      $("#currentIndex").text(currentScanIndex);

    } else {
      // Add new index
      var row = parseInt($cell.attr('data-row'));
      var col = parseInt($cell.attr('data-col'));

      $cell.addClass('selected');
      $cell.attr('data-index', currentScanIndex);
      $cell.text(currentScanIndex);

      // Add to data array
      scannerArrayData.push({
        row: row,
        col: col,
        index: currentScanIndex
      });

      currentScanIndex++;
      $("#currentIndex").text(currentScanIndex);
    }
  });

  // Clear all path
  $('#btnClearScannerPath').click(function (e) {
    e.preventDefault();

    if (scannerArrayData.length > 0) {
      if (!confirm("Clear all selected path?")) {
        return;
      }
    }

    $('.scanner-array-grid td').each(function() {
      $(this).removeClass('selected');
      $(this).attr('data-index', '0');
      $(this).text('');
    });

    scannerArrayData = [];
    currentScanIndex = 1;
    $("#currentIndex").text(currentScanIndex);
  });

  // Save all to database
  $('#btnSaveScannerArray').click(function (e) {
    e.preventDefault();

    if (scannerArrayData.length === 0) {
      alert("Please define a scan path by clicking cells in the grid.");
      return;
    }

    var v_partid = $("#txtPartID").val();
    var v_MasterID = $("#ddlMasterID").find("option:selected").text();
    var v_PositionID = $("#ddlPositionID").find("option:selected").text();

    if (!v_MasterID || v_MasterID === "") {
      alert("Please select a Scanner.");
      return;
    }

    if (!v_PositionID || v_PositionID === "") {
      alert("Please select a Position.");
      return;
    }

    // Build array of requests
    var requests = scannerArrayData.map(function(item) {
      return {
        PartID: v_partid,
        Row: item.row,
        Col: item.col,
        MasterID: v_MasterID,
        PositionID: v_PositionID,
        ToIndex: item.index
      };
    });

    // Show confirmation
    var confirmMsg = "Save " + requests.length + " scanner array positions?\n\n";
    confirmMsg += "Scanner: " + v_MasterID + "\n";
    confirmMsg += "Position: " + v_PositionID + "\n";
    confirmMsg += "Path: " + requests.length + " cells";

    if (!confirm(confirmMsg)) {
      return;
    }

    // Disable button during save
    $(this).prop('disabled', true).val('Saving...');

    // Send all requests
    var successCount = 0;
    var errorCount = 0;

    requests.forEach(function(req, index) {
      $.ajax({
        type: "POST",
        url: "/Engineering/PartNumber/AddActivateScannerArrayList",
        async: false,
        contentType: "application/json; charset=utf-8",
        data: JSON.stringify(req),
        success: function () {
          successCount++;
        },
        error: function() {
          errorCount++;
        }
      });
    });

    // Re-enable button
    $('#btnSaveScannerArray').prop('disabled', false).val('Save All');

    // Show results
    if (errorCount === 0) {
      alert("Successfully saved " + successCount + " scanner array positions!");

      // Clear the grid
      $('#btnClearScannerPath').click();

      // Reload the grid
      updateActivateScannerArray();
    } else {
      alert("Completed with " + successCount + " successful and " + errorCount + " failed saves.");
      updateActivateScannerArray();
    }
  });

  function updateActivateScannerArray() {
    var grid = new MvcGrid(document.querySelector('#mvcActivateScannerArrayList'));
    grid.requestType = 'post';
    grid.reload();
  };

  $(document).on('click', '#mvcActivateScannerArrayList>table>tbody>tr>td>a.DeleteActivateScannerArrayList', function (e) {
    e.preventDefault();
    var target = $(this).attr("href");

    $.ajax({
      type: "POST",
      url: target,
      async: false,
      contentType: "application/json; charset=utf-8",
      success: function () {
        updateActivateScannerArray();
      }
    })
  });
</script>

