        <script type="text/javascript" nonce="@Html.ScriptNonce()">
            $('#btnUploadParameters').click(function (e) {
              e.preventDefault(); // <------------------ stop default behaviour of button
              // Load new data
              var v_areaid = $("#ddlareaid2").val();
              var v_substation = $("#ddlsubstation2").val();
              var v_partid = $("#txtPartID").val();
              var v_ParametersSide = $("#ddlParametersSide").val();

              var v_Link = $("#txtfileparametersurl").val();

              if (!$("#txtfileparametersurl").val()) {
                v_Link = "na";
              }

              var nurl = ""

              const fi = document.getElementById('txtfileparameters');

              if (fi.files.length > 0) {
                for (var i = 0; i <= fi.files.length - 1; i++) {
                  const fsize = fi.files.item(i).size;
                  const file = Math.round((fsize / 1024));
                  // The size of the file.
                  if (file >= 15096) {
                    alert(
                      "File too Big, please select a file less than 15mb");
                    $("#txtfileparameters").html("");
                  }
                }

                var fileUpload = $("#txtfileparameters").get(0);
                var files = fileUpload.files;

                var fileData = new FormData();

                // Looping over all files and add it to FormData object
                for (var i = 0; i < files.length; i++) {
                  fileData.append(files[i].name, files[i]);
                }
                //// Adding one more key to FormData object
                //fileData.append('username', ‘Manas’);

                var v_nomber = @Model.PartID + '_' + v_ParametersSide + '_' + v_substation + '_' + '@today.ToString("yyMMdd")';

                fileData.append("Names", v_nomber);

                //var req2 = { v_AutoID: v_AutoID, nombre: v_nomber };

                $.ajax({
                  type: "POST",
                  url: "/Engineering/PartNumber/UploadParameterSheet",
                  async: false,
                  data: fileData,
                  contentType: false,
                  processData: false,
                  success: function (response) {
                    nurl = response;

                    //$("#txtfileparameters").val(v_nomber);

                  },
                  error: function () {

                  }
                });
              }

              var req = { AreaID: v_areaid, partid: v_partid, StationID: v_substation, UrlWeb: v_Link, nurl: nurl, ParametersSide: v_ParametersSide };

              $.ajax({
                type: "POST",
                url: "/Engineering/PartNumber/AddParametersSheet",
                async: false,
                contentType: "application/json; charset=utf-8",
                data: JSON.stringify(req),
                success: function () {
                  // Reload Grid
                  updateParametersSheet();
                }
              })
            });

            function updateParametersSheet() {
              var grid = new MvcGrid(document.querySelector('#mvcParametersSheet'));
              grid.requestType = 'post';
              grid.reload();
            };

            $(document).on('click', '#mvcParametersSheet>table>tbody>tr>td>a.delRow', function (e) {
              e.preventDefault(); // <------------------ stop default behaviour of button
              var target = $(this).attr("href");

              $.ajax({
                type: "POST",
                url: target,
                async: false,
                contentType: "application/json; charset=utf-8",
                success: function () {
                  // Reload Grid
                  updateParametersSheet();
                }
              })
            });
        </script>
      </li>
