        <script type="text/javascript" nonce="@Html.ScriptNonce()">
          $('#btnAddLaserSkip').click(function (e) {
            e.preventDefault();
            var v_PartId = $("#txtPartID").val();

            if (v_PartId == '' || v_PartId == 0) {
              UIkit.modal.alert('Part ID is required');
              return false;
            }

            var url = '@Url.Action("AddLaserSkip", "PartNumber")';
            $.ajax({
              data: { PartID: v_PartId },
              type: "POST",
              url: url,
              async: false,
              contentType: "application/json; charset=utf-8",
              success: function (data) {
                updateLaserSkip();
              },
              error: function () {
                UIkit.modal.alert('Error adding laser skip configuration');
              }
            });
          });

          function updateLaserSkip() {
            new MvcGrid(document.querySelector('#mvcLaserSkip')).reload();
          }

          $(document).on('click', '#mvcLaserSkip>table>tbody>tr>td>a.delRow', function (e) {
            e.preventDefault();
            var target = $(this).attr('href');
            UIkit.modal.confirm('Are you sure you want to delete this configuration?', function () {
              $.ajax({
                type: "POST",
                url: target,
