                  <span style="margin-left: 10px;">Scanner: <strong id="activeScanner">--</strong></span>
                  <span style="margin-left: 15px;">Position: <strong id="activePosition">--</strong></span>
                  <span style="margin-left: 15px; color: #666; font-style: italic;">Click cells to auto-assign</span>
                </div>
              </div>

              <div id="scannerArrayStatus" style="margin-top: 10px; display: none;">
                <span class="scanner-status">Next Index: <span id="currentIndex">1</span></span>
                <span style="color: #666;">Click cells to configure. Click again to edit.</span>
              </div>
