                    new SelectListItem { Text = "InSight Vision Cognex", Value = "InSight Vision Cognex", Selected = true }
              }, new { @class = "md-input", id = "intTcpTypeAreasTCP" })
            </div>
          </div>
          <div>
            <div class="p-0 input-group mb-3 mn-r-10">
              @Html.Label("SLAVE", new { @class = "m-0 fs-14" })
              @Html.DropDownList("numero", (IEnumerable<SelectListItem>)SlaveNumTCP, new { @class = "md-input", id = "intSlaveAreasTCP" })
            </div>
