            var v_Side = $("#intSideAreasTCP").val();
            var v_IP = $("#intIPAreasTCP").val();
            var v_Port = $("#intPortAreasTCP").val();
            var v_ClientServer = $("#intClientServerAreasTCP").val();
            var v_TcpType = $("#intTcpTypeAreasTCP").val();
            var v_Slave = $("#intSlaveAreasTCP").val();

            var req = { PartID: v_PartId, AreaID: v_AreaID, Side: v_Side, IP: v_IP, Port: v_Port, CLIENTORSERVER: v_ClientServer, TCPTYPE: v_TcpType, Slave: v_Slave };

