          var binlist = Firstronic.Framework.Queries.GetSelectedFromQuery("SELECT [Group_ID] ,[Group_Name] FROM [Part_Parent] WHERE 1=0", idParameters);

          var optionsParent = new List<SelectListItem>();

          var o = new SelectListItem
          {
            Value = "false",
