          function updateGroupsChilds() {
            var grid = new MvcGrid(document.querySelector('#mvcGroupsChilds'));
            grid.requestType = 'post';
            grid.reload();
          };

          $(document).on('click', '#mvcGroupsChilds>table>tbody>tr>td>a.delRow', function (e) {
            e.preventDefault(); // <------------------ stop default behaviour of button
            var target = $(this).attr("href");

            $.ajax({
