            font-weight: bold;
            border-color: #388E3C;
          }
          .scanner-array-grid td.selected:hover {
            background: #66BB6A;
          }
          .cell-index {
            font-size: 24px;
            font-weight: bold;
            display: block;
          }
          .cell-info {
            font-size: 9px;
            display: block;
            margin-top: 2px;
            opacity: 0.9;
          }
          .scanner-controls {
            margin: 15px 0;
            padding: 15px;
            background: #f9f9f9;
            border-radius: 4px;
            border: 1px solid #ddd;
          }
          .scanner-status {
            display: inline-block;
            padding: 8px 15px;
            background: #2196F3;
            color: white;
            border-radius: 4px;
            margin-right: 15px;
            font-weight: bold;
          }
          #scannerArrayContainer {
            overflow-x: auto;
          }
          .modal-overlay {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0,0,0,0.5);
            z-index: 9999;
            justify-content: center;
            align-items: center;
          }
          .modal-content {
            background: white;
            padding: 25px;
            border-radius: 8px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.3);
            min-width: 400px;
            max-width: 500px;
          }
          .modal-header {
            font-size: 18px;
            font-weight: bold;
            margin-bottom: 20px;
            color: #333;
            border-bottom: 2px solid #2196F3;
            padding-bottom: 10px;
          }
          .modal-body {
            margin: 20px 0;
          }
          .modal-footer {
            display: flex;
            justify-content: flex-end;
            gap: 10px;
            margin-top: 20px;
          }
          .form-row {
            margin-bottom: 15px;
          }
          .form-row label {
            display: block;
            margin-bottom: 5px;
            font-weight: bold;
            color: #555;
          }
          .form-row select,
          .form-row input {
            width: 100%;
            padding: 8px;
            border: 1px solid #ddd;
            border-radius: 4px;
          }
        </style>

        <!-- Cell Configuration Modal -->
        <div id="cellConfigModal" class="modal-overlay">
          <div class="modal-content">
            <div class="modal-header">
              Configure Scanner Array Cell
            </div>
            <div class="modal-body">
              <div class="form-row">
                <label>Position:</label>
                <input type="text" id="modalCellPosition" readonly style="background: #f0f0f0;" />
              </div>
              <div class="form-row">
                <label>Index:</label>
                <input type="number" id="modalCellIndex" readonly style="background: #f0f0f0;" />
              </div>
              <div class="form-row">
                <label>Scanner:</label>
                <select id="modalScanner" class="md-input">
                  @foreach (var item in (IEnumerable<SelectListItem>)sublist_MasterID)
                  {
                    <option value="@item.Text">@item.Text</option>
                  }
                </select>
              </div>
              <div class="form-row">
                <label>Position ID:</label>
                <select id="modalPosition" class="md-input">
                  @foreach (var item in (IEnumerable<SelectListItem>)sublist_PositionID)
                  {
                    <option value="@item.Text">@item.Text</option>
                  }
                </select>
              </div>
            </div>
            <div class="modal-footer">
              <button id="btnModalRemove" class="md-btn md-btn-danger md-btn-small" style="display:none;">Remove</button>
              <button id="btnModalCancel" class="md-btn md-btn-flat md-btn-small">Cancel</button>
              <button id="btnModalSave" class="md-btn md-btn-primary md-btn-small">Save</button>
            </div>
          </div>
        </div>

        <div class="uk-grid">
          <div class="uk-width-1-1">
            <div class="scanner-controls">
              <div class="uk-grid">
                <div class="uk-width-1-1">
                  <div style="display: flex; align-items: flex-end; gap: 10px; margin-bottom: 15px;">
                    <input id="btnGenerateScannerGrid" type="button" value="Generate Grid" class="md-btn md-btn-primary md-btn-small" />
                    <input id="btnLoadExistingData" type="button" value="Load Existing" class="md-btn md-btn-primary md-btn-small" />
                    <input id="btnClearScannerPath" type="button" value="Clear All" class="md-btn md-btn-warning md-btn-small" style="display:none;" />
                    <input id="btnSaveScannerArray" type="button" value="Save All" class="md-btn md-btn-success md-btn-small" style="display:none;" />
                  </div>
                </div>
              </div>

              <!-- Quick Mode Configuration -->
              <div style="background: #e3f2fd; padding: 15px; border-radius: 4px; border: 2px solid #2196F3; margin-bottom: 15px;">
                <div style="display: flex; align-items: center; margin-bottom: 10px;">
                  <input type="checkbox" id="chkQuickMode" style="width: auto; margin-right: 10px;" />
                  <label for="chkQuickMode" style="margin: 0; font-weight: bold; color: #1976D2; cursor: pointer;">
                    Enable Quick Mode (Auto-assign Scanner & Position)
                  </label>
                </div>
                <div class="uk-grid" id="quickModeOptions" style="display: none;">
                  <div class="uk-width-1-3@m">
                    <div class="input-group mb-3">
                      <label class="m-0 fs-14" style="font-weight: bold;">Default Scanner:</label>
                      <select id="ddlDefaultScanner" class="md-input">
                        <option value="">-- Select Scanner --</option>
                        @foreach (var item in (IEnumerable<SelectListItem>)sublist_MasterID)
                        {
                          <option value="@item.Text">@item.Text</option>
                        }
                      </select>
                    </div>
                  </div>
                  <div class="uk-width-1-3@m">
                    <div class="input-group mb-3">
                      <label class="m-0 fs-14" style="font-weight: bold;">Default Position:</label>
                      <select id="ddlDefaultPosition" class="md-input">
                        <option value="">-- Select Position --</option>
                        @foreach (var item in (IEnumerable<SelectListItem>)sublist_PositionID)
                        {
                          <option value="@item.Text">@item.Text</option>
                        }
                      </select>
                    </div>
                  </div>
                  <div class="uk-width-1-3@m">
                    <div class="input-group mb-3">
                      <label class="m-0 fs-14" style="font-weight: bold;">Auto Position:</label>
                      <select id="ddlAutoPositionMode" class="md-input">
                        <option value="same">Same for All</option>
                        <option value="increment">Auto Increment (1, 2, 3...)</option>
                      </select>
                    </div>
                  </div>
                </div>
                <div id="quickModeActive" style="display: none; margin-top: 10px; padding: 10px; background: #fff; border-radius: 4px; border-left: 4px solid #4CAF50;">
                  <strong style="color: #2E7D32;">Quick Mode Active:</strong>
                  <span style="margin-left: 10px;">Scanner: <strong id="activeScanner">--</strong></span>
                  <span style="margin-left: 15px;">Position: <strong id="activePosition">--</strong></span>
                  <span style="margin-left: 15px; color: #666; font-style: italic;">Click cells to auto-assign</span>
                </div>
              </div>

              <div id="scannerArrayStatus" style="margin-top: 10px; display: none;">
                <span class="scanner-status">Next Index: <span id="currentIndex">1</span></span>
                <span style="color: #666;">Click cells to configure. Click again to edit.</span>
              </div>
            </div>
          </div>

          <div class="uk-width-1-1">
            <div id="scannerArrayContainer"></div>
          </div>
        </div>

        <script type="text/javascript" nonce="@Html.ScriptNonce()">
          var scannerArrayData = [];
          var currentScanIndex = 1;
          var currentEditCell = null;
          var quickModeEnabled = false;
          var autoPositionCounter = 1;

          // Quick Mode Toggle
          $('#chkQuickMode').change(function () {
            quickModeEnabled = $(this).is(':checked');

            if (quickModeEnabled) {
              $('#quickModeOptions').show();
              updateQuickModeStatus();
            } else {
              $('#quickModeOptions').hide();
              $('#quickModeActive').hide();
            }
          });

          // Update Quick Mode display when scanner/position changes
          $('#ddlDefaultScanner, #ddlDefaultPosition, #ddlAutoPositionMode').change(function () {
            updateQuickModeStatus();
          });

          function updateQuickModeStatus() {
            var scanner = $('#ddlDefaultScanner').val();
            var position = $('#ddlDefaultPosition').val();

            if (quickModeEnabled && scanner && position) {
              $('#activeScanner').text(scanner);

              var posMode = $('#ddlAutoPositionMode').val();
              if (posMode === 'increment') {
                $('#activePosition').text(position + ' (Auto: ' + autoPositionCounter + ')');
              } else {
                $('#activePosition').text(position);
              }

              $('#quickModeActive').show();
            } else {
              $('#quickModeActive').hide();
            }
          }

          // Load existing data from the grid
          $('#btnLoadExistingData').click(function (e) {
            e.preventDefault();

            var v_partid = $("#txtPartID").val();

            // First, try to load grid size from database
            $.ajax({
              type: "GET",
              url: "/Engineering/PartNumber/GetActivateScannerArraySize",
              data: { id: v_partid },
              success: function (sizeData) {
                var rows = 0;
                var cols = 0;

                if (sizeData && sizeData.Rows && sizeData.Cols) {
                  rows = sizeData.Rows;
                  cols = sizeData.Cols;
                  $("#ddlRows").val(rows);
                  $("#ddlCols").val(cols);
                }

                // Load cell data
                loadCellData(v_partid, rows, cols);
              },
              error: function() {
                // If size table doesn't exist or has no data, load cell data anyway
                loadCellData(v_partid, 0, 0);
              }
            });
          });

          function loadCellData(partid, rows, cols) {
            $.ajax({
              type: "GET",
              url: "/Engineering/PartNumber/GetSubActivateScannerArrayList",
              data: { id: partid },
              success: function (response) {
                if (response && response.Modelo && response.Modelo.length > 0) {
                  var maxRow = rows;
                  var maxCol = cols;

                  // If we don't have size from database, find max from data
                  if (maxRow === 0 || maxCol === 0) {
                    response.Modelo.forEach(function(item) {
                      if (item.Row > maxRow) maxRow = item.Row;
                      if (item.Col > maxCol) maxCol = item.Col;
                    });

                    // Update the Rows and Cols fields
                    $("#ddlRows").val(maxRow);
                    $("#ddlCols").val(maxCol);
                  }

                  // Generate grid
                  generateGrid(maxRow, maxCol);

                  // Populate cells with existing data
                  response.Modelo.forEach(function(item) {
                    var $cell = $(`.scanner-array-grid td[data-row="${item.Row}"][data-col="${item.Col}"]`);
                    if ($cell.length > 0) {
                      $cell.addClass('selected');
                      $cell.attr('data-index', item.ToIndex);
                      $cell.attr('data-scanner', item.MasterID || '');
                      $cell.attr('data-position', item.PositionID || '');

                      var cellHtml = '<span class="cell-index">' + item.ToIndex + '</span>';
                      if (item.MasterID) {
                        cellHtml += '<span class="cell-info">S:' + item.MasterID + '</span>';
                      }
                      if (item.PositionID) {
                        cellHtml += '<span class="cell-info">P:' + item.PositionID + '</span>';
                      }
                      $cell.html(cellHtml);

                      scannerArrayData.push({
                        row: item.Row,
                        col: item.Col,
                        index: item.ToIndex,
                        scanner: item.MasterID || '',
                        position: item.PositionID || ''
                      });

                      if (item.ToIndex >= currentScanIndex) {
                        currentScanIndex = item.ToIndex + 1;
                      }
                    }
                  });

                  $("#currentIndex").text(currentScanIndex);
                  alert("Loaded " + response.Modelo.length + " existing scanner positions.");
                } else {
                  alert("No existing data found. Please use 'Generate Grid' to create a new configuration.");
                }
              },
              error: function() {
                alert("Error loading existing data.");
              }
            });
          }

          // Generate the grid based on Rows and Cols inputs
          $('#btnGenerateScannerGrid').click(function (e) {
            e.preventDefault();

            var rows = parseInt($("#ddlRows").val());
            var cols = parseInt($("#ddlCols").val());
            var v_partid = $("#txtPartID").val();

            if (isNaN(rows) || isNaN(cols) || rows < 1 || cols < 1) {
              alert("Please enter valid Rows and Cols values first (above in the Activate Scanner section).");
              return;
            }

            if (rows > 20 || cols > 20) {
              if (!confirm("Grid size is large (" + rows + "x" + cols + "). Continue?")) {
                return;
              }
            }

            // Save grid size to database
            var sizeReq = { PartID: v_partid, Rows: rows, Cols: cols };

            $.ajax({
              type: "POST",
              url: "/Engineering/PartNumber/SaveActivateScannerArraySize",
              async: false,
              contentType: "application/json; charset=utf-8",
              data: JSON.stringify(sizeReq),
              success: function () {
                // Reset data
                scannerArrayData = [];
                currentScanIndex = 1;
                autoPositionCounter = 1;
                $("#currentIndex").text(currentScanIndex);

                generateGrid(rows, cols);
              },
              error: function() {
                alert("Warning: Could not save grid size to database. Grid will still be generated.");

                // Reset data
                scannerArrayData = [];
                currentScanIndex = 1;
                autoPositionCounter = 1;
                $("#currentIndex").text(currentScanIndex);

                generateGrid(rows, cols);
              }
            });
          });

          function generateGrid(rows, cols) {
            // Build grid HTML
            var gridHtml = '<table class="scanner-array-grid"><thead><tr><th></th>';

            // Column headers
            for (var c = 1; c <= cols; c++) {
              gridHtml += '<th>Col ' + c + '</th>';
            }
            gridHtml += '</tr></thead><tbody>';

            // Rows
            for (var r = 1; r <= rows; r++) {
              gridHtml += '<tr><th>Row ' + r + '</th>';
              for (var c = 1; c <= cols; c++) {
                gridHtml += '<td data-row="' + r + '" data-col="' + c + '" data-index="0" data-scanner="" data-position=""></td>';
              }
              gridHtml += '</tr>';
            }

            gridHtml += '</tbody></table>';

            $('#scannerArrayContainer').html(gridHtml);
            $('#scannerArrayStatus').show();
            $('#btnClearScannerPath').show();
            $('#btnSaveScannerArray').show();
          }

          // Handle cell clicks - Quick Mode or Modal
          $(document).on('click', '.scanner-array-grid td', function (e) {
            var $cell = $(this);
            var row = parseInt($cell.attr('data-row'));
            var col = parseInt($cell.attr('data-col'));
            var currentIndex = parseInt($cell.attr('data-index'));
            var scanner = $cell.attr('data-scanner') || '';
            var position = $cell.attr('data-position') || '';

            // If Quick Mode is enabled and cell is empty, auto-assign
            if (quickModeEnabled && currentIndex === 0) {
              var defaultScanner = $('#ddlDefaultScanner').val();
              var defaultPosition = $('#ddlDefaultPosition').val();
              var posMode = $('#ddlAutoPositionMode').val();

              if (!defaultScanner || !defaultPosition) {
                alert("Please select Default Scanner and Position for Quick Mode.");
                return;
              }

              // Calculate position value
              var positionValue = defaultPosition;
              if (posMode === 'increment') {
                positionValue = autoPositionCounter;
                autoPositionCounter++;
              }

              // Auto-assign
              var newIndex = currentScanIndex;
              currentScanIndex++;
              $("#currentIndex").text(currentScanIndex);

              $cell.addClass('selected');
              $cell.attr('data-index', newIndex);
              $cell.attr('data-scanner', defaultScanner);
              $cell.attr('data-position', positionValue);

              var cellHtml = '<span class="cell-index">' + newIndex + '</span>';
              cellHtml += '<span class="cell-info">S:' + defaultScanner + '</span>';
              cellHtml += '<span class="cell-info">P:' + positionValue + '</span>';
              $cell.html(cellHtml);

              scannerArrayData.push({
                row: row,
                col: col,
                index: newIndex,
                scanner: defaultScanner,
                position: positionValue
              });

              // Update quick mode status display
              updateQuickModeStatus();

              return; // Don't show modal
            }

            // Otherwise, show modal for manual configuration or editing
            currentEditCell = $cell;

            // Set modal values
            $('#modalCellPosition').val('Row ' + row + ', Col ' + col);

            if (currentIndex > 0) {
              // Editing existing cell
              $('#modalCellIndex').val(currentIndex);
              $('#modalScanner').val(scanner);
              $('#modalPosition').val(position);
              $('#btnModalRemove').show();
            } else {
              // Adding new cell manually
              $('#modalCellIndex').val(currentScanIndex);
              $('#modalScanner').val($('#modalScanner option:first').val());
              $('#modalPosition').val($('#modalPosition option:first').val());
              $('#btnModalRemove').hide();
            }

            // Show modal
            $('#cellConfigModal').css('display', 'flex');
          });

          // Modal Save button
          $('#btnModalSave').click(function () {
            var $cell = currentEditCell;
            var row = parseInt($cell.attr('data-row'));
            var col = parseInt($cell.attr('data-col'));
            var currentIndex = parseInt($cell.attr('data-index'));
            var newIndex = parseInt($('#modalCellIndex').val());
            var scanner = $('#modalScanner').val();
            var position = $('#modalPosition').val();

            if (!scanner || !position) {
              alert("Please select both Scanner and Position.");
              return;
            }

            // If new cell, assign next index
            if (currentIndex === 0) {
              newIndex = currentScanIndex;
              currentScanIndex++;
              $("#currentIndex").text(currentScanIndex);
            }

            // Update cell
            $cell.addClass('selected');
            $cell.attr('data-index', newIndex);
            $cell.attr('data-scanner', scanner);
            $cell.attr('data-position', position);

            var cellHtml = '<span class="cell-index">' + newIndex + '</span>';
            cellHtml += '<span class="cell-info">S:' + scanner + '</span>';
            cellHtml += '<span class="cell-info">P:' + position + '</span>';
            $cell.html(cellHtml);

            // Update data array
            var existingItem = scannerArrayData.find(function(item) {
              return item.row === row && item.col === col;
            });

            if (existingItem) {
              existingItem.scanner = scanner;
              existingItem.position = position;
            } else {
              scannerArrayData.push({
                row: row,
                col: col,
                index: newIndex,
                scanner: scanner,
                position: position
              });
            }

            // Close modal
            $('#cellConfigModal').hide();
          });

          // Modal Remove button
          $('#btnModalRemove').click(function () {
            var $cell = currentEditCell;
            var row = parseInt($cell.attr('data-row'));
            var col = parseInt($cell.attr('data-col'));
            var removedIndex = parseInt($cell.attr('data-index'));

            // Remove from data array
            scannerArrayData = scannerArrayData.filter(function(item) {
              return !(item.row === row && item.col === col);
            });

            // Update all cells with higher index
            $('.scanner-array-grid td').each(function() {
              var idx = parseInt($(this).attr('data-index'));
              if (idx > removedIndex) {
                var newIdx = idx - 1;
                $(this).attr('data-index', newIdx);

                var scanner = $(this).attr('data-scanner');
                var position = $(this).attr('data-position');

                var cellHtml = '<span class="cell-index">' + newIdx + '</span>';
                if (scanner) cellHtml += '<span class="cell-info">S:' + scanner + '</span>';
                if (position) cellHtml += '<span class="cell-info">P:' + position + '</span>';
                $(this).html(cellHtml);

                // Update in data array
                var r = parseInt($(this).attr('data-row'));
                var c = parseInt($(this).attr('data-col'));
                scannerArrayData.forEach(function(item) {
                  if (item.row === r && item.col === c) {
                    item.index = newIdx;
                  }
                });
              }
            });

            // Clear this cell
            $cell.removeClass('selected');
            $cell.attr('data-index', '0');
            $cell.attr('data-scanner', '');
            $cell.attr('data-position', '');
            $cell.html('');

            // Update counter
            currentScanIndex--;
            $("#currentIndex").text(currentScanIndex);

            // Close modal
            $('#cellConfigModal').hide();
          });

          // Modal Cancel button
          $('#btnModalCancel').click(function () {
            $('#cellConfigModal').hide();
          });

          // Close modal when clicking outside
          $('#cellConfigModal').click(function (e) {
            if (e.target.id === 'cellConfigModal') {
              $(this).hide();
            }
          });

          // Clear all path
          $('#btnClearScannerPath').click(function (e) {
            e.preventDefault();

            if (scannerArrayData.length > 0) {
              if (!confirm("Clear all selected cells?")) {
                return;
              }
            }

            $('.scanner-array-grid td').each(function() {
              $(this).removeClass('selected');
              $(this).attr('data-index', '0');
              $(this).attr('data-scanner', '');
              $(this).attr('data-position', '');
              $(this).html('');
            });

            scannerArrayData = [];
            currentScanIndex = 1;
            $("#currentIndex").text(currentScanIndex);
          });

          // Save all to database
          $('#btnSaveScannerArray').click(function (e) {
            e.preventDefault();

            if (scannerArrayData.length === 0) {
              alert("Please configure at least one cell.");
              return;
            }

            // Validate all cells have scanner and position
            var invalidCells = scannerArrayData.filter(function(item) {
              return !item.scanner || !item.position;
            });

            if (invalidCells.length > 0) {
              alert("Some cells are missing Scanner or Position. Please configure all cells.");
              return;
            }

            var v_partid = $("#txtPartID").val();

            // Build array of requests
            var requests = scannerArrayData.map(function(item) {
              return {
                PartID: v_partid,
                Row: item.row,
                Col: item.col,
                MasterID: item.scanner,
                PositionID: item.position,
                ToIndex: item.index
              };
            });

            // Show confirmation
            var confirmMsg = "Save " + requests.length + " scanner array positions?";

            if (!confirm(confirmMsg)) {
              return;
            }

            // Disable button during save
            $(this).prop('disabled', true).val('Saving...');

            // Send all requests
            var successCount = 0;
            var errorCount = 0;

            requests.forEach(function(req, index) {
              $.ajax({
                type: "POST",
                url: "/Engineering/PartNumber/AddActivateScannerArrayList",
                async: false,
                contentType: "application/json; charset=utf-8",
                data: JSON.stringify(req),
                success: function () {
                  successCount++;
                },
                error: function() {
                  errorCount++;
                }
              });
            });

            // Re-enable button
            $('#btnSaveScannerArray').prop('disabled', false).val('Save All');

            // Show results
            if (errorCount === 0) {
              alert("Successfully saved " + successCount + " scanner array positions!");

              // Reload the grid
              updateActivateScannerArray();
            } else {
              alert("Completed with " + successCount + " successful and " + errorCount + " failed saves.");
              updateActivateScannerArray();
            }
          });

          function updateActivateScannerArray() {
            var grid = new MvcGrid(document.querySelector('#mvcActivateScannerArrayList'));
            grid.requestType = 'post';
            grid.reload();
          };

          $(document).on('click', '#mvcActivateScannerArrayList>table>tbody>tr>td>a.DeleteActivateScannerArrayList', function (e) {
            e.preventDefault();
            var target = $(this).attr("href");

            $.ajax({
              type: "POST",
              url: target,
              async: false,
              contentType: "application/json; charset=utf-8",
              success: function () {
                updateActivateScannerArray();
              }
            })
          });
        </script>
      </li>
      @*-------------------------------------------------------------------------------------------SERIALIZATION ORDER----------*@
      <li aria-hidden="true">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">Serialization Order.</p>
          </div>
        </div>
        @{

          DataTable dt_Array_Index = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT TOP (1000)[ToIndex],[Row],[Col],[MasterID], [PositionID] FROM [Part_Operation_Serialization_Array_Index] where PartID=@PartID ", idParameters);

        }
        <div class="arrow-1"></div>
        <div class="uk-grid-small  uk-grid-match uk-grid" uk-grid>
          @{
            int contador = 0;
            int ColMax = Firstronic.Framework.Queries.GetIntFromQuery("select MAX(Col) as Col   from Part_Operation_Serialization_Array_Index where PartID=@PartID", idParameters);
            foreach (DataRow row in dt_Array_Index.Rows)
            {
              <div class="uk-width-1-5@s uk-width-1-10@m">
                <div class="md-card innerlink">
                  <div class="md-card-content">
                    <h3 class="heading_a uk-margin-bottom">Index = @row["ToIndex"].ToString() ScannerNo = @row["MasterID"].ToString()  Position = @row["PositionID"].ToString()   </h3>
                  </div>
                </div>
              </div>

              contador++;
