                @Html.DropDownList("ddlSMBArea", (IEnumerable<SelectListItem>)arealistSBM, "-- Select Area --", new { @class = "uk-select" })
              </div>
              <div class="uk-width-1-6@m">
                <label class="uk-form-label">Side <span class="uk-text-danger">*</span></label>
                @Html.DropDownList("ddlSMBSide", new SelectList(new[] {
                  new { Value = "A", Text = "A" },
                  new { Value = "B", Text = "B" }
                }, "Value", "Text"), "-- Select --", new { @class = "uk-select" })
              </div>
              <div class="uk-width-1-3@m">
                <label class="uk-form-label">SMB Path <span class="uk-text-danger">*</span></label>
                @Html.TextBox("txtSMBPath", "", new { @class = "uk-input", placeholder = @"\\server\share\folder" })
              </div>
              <div class="uk-width-1-6@m">
                <label class="uk-form-label">File Pattern</label>
                @Html.TextBox("txtSMBFilePattern", "*.TXT", new { @class = "uk-input" })
              </div>
              <div class="uk-width-1-6@m">
                <label class="uk-form-label">Interval (ms)</label>
                @Html.TextBox("txtSMBInterval", "5000", new { @class = "uk-input", type = "number" })
              </div>
              <div class="uk-width-1-4@m">
                <label class="uk-form-label">SMB Type</label>
                @Html.DropDownList("ddlSMBType", new SelectList(new[] {
                  new { Value = "InSight Vision Cognex", Text = "InSight Vision Cognex" },
                  new { Value = "Material Data", Text = "Material Data" },
                  new { Value = "Serial Import", Text = "Serial Import" },
                  new { Value = "Custom", Text = "Custom" }
                }, "Value", "Text"), "-- Select Type --", new { @class = "uk-select" })
              </div>
              <div class="uk-width-1-6@m">
                <label class="uk-form-label">&nbsp;</label>
                <label><input id="chkSMBEnabled" type="checkbox" class="uk-checkbox" checked /> Enabled</label>
              </div>
            </div>

            <hr class="uk-divider-small" />
            <h5 class="uk-heading-line"><span>Network Credentials (Optional)</span></h5>
            <p class="uk-text-small uk-text-muted">Leave blank to use Windows authentication. Provide credentials only if accessing network share requires different user.</p>

            <div class="uk-grid-small" uk-grid>
              <div class="uk-width-1-3@m">
                <label class="uk-form-label">Domain</label>
                @Html.TextBox("txtSMBDomain", "", new { @class = "uk-input", placeholder = "DOMAIN or WORKGROUP" })
              </div>
              <div class="uk-width-1-3@m">
                <label class="uk-form-label">Username</label>
                @Html.TextBox("txtSMBUsername", "", new { @class = "uk-input", placeholder = "username or DOMAIN\\username" })
              </div>
              <div class="uk-width-1-3@m">
                <label class="uk-form-label">Password</label>
                @Html.Password("txtSMBPassword", "", new { @class = "uk-input", placeholder = "••••••••", autocomplete = "off" })
              </div>
            </div>

            <div class="uk-grid-small uk-margin-top" uk-grid>
              <div class="uk-width-1-1@m">
                <button id="btnAddSMBPath" type="button" class="uk-button uk-button-primary uk-button-small">
                  <span uk-icon="icon: plus"></span> Add SMB Path
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <script type="text/javascript" nonce="@Html.ScriptNonce()">
        $('#btnAddSMBPath').click(function (e) {
          e.preventDefault();

          var partId = $("#txtPartID").val();
          var areaId = $("#ddlSMBArea").val();
          var side = $("#ddlSMBSide").val();
          var smbPath = $("#txtSMBPath").val();
          var filePattern = $("#txtSMBFilePattern").val();
          var interval = $("#txtSMBInterval").val();
          var smbType = $("#ddlSMBType").val();
          var enabled = $("#chkSMBEnabled").is(':checked');
          var domain = $("#txtSMBDomain").val();
          var username = $("#txtSMBUsername").val();
          var password = $("#txtSMBPassword").val();

          if (!areaId || !side || !smbPath) {
            UIkit.modal.alert('Please fill in all required fields (Area, Side, SMB Path)');
            return false;
          }

          var req = {
            PartID: partId,
            AreaID: areaId,
            Side: side,
            SMB_PATH: smbPath,
            SMB_FILE_PATTERN: filePattern,
            SMB_READ_INTERVAL: interval,
            SMB_ENABLED: enabled,
            SMB_TYPE: smbType,
            SMB_DOMAIN: domain,
            SMB_USERNAME: username,
            SMB_PASSWORD: password
          };

          $.ajax({
            type: "POST",
            url: "/Engineering/PartNumber/AddSMBPath",
            async: false,
            contentType: "application/json; charset=utf-8",
            data: JSON.stringify(req),
            success: function () {
              updateSMBPathsList();
              $("#ddlSMBArea").val("");
              $("#ddlSMBSide").val("");
              $("#txtSMBPath").val("");
              $("#txtSMBFilePattern").val("*.TXT");
              $("#txtSMBInterval").val("5000");
              $("#ddlSMBType").val("");
              $("#chkSMBEnabled").prop('checked', true);
              $("#txtSMBDomain").val("");
              $("#txtSMBUsername").val("");
              $("#txtSMBPassword").val("");
            },
            error: function (xhr, status, error) {
              UIkit.modal.alert('Error adding SMB path: ' + error);
            }
          });
        });

        function updateSMBPathsList() {
          var grid = new MvcGrid(document.querySelector('#mvcSMBPathsList'));
          grid.requestType = 'post';
          grid.reload();
        };

        $(document).on('click', '#mvcSMBPathsList>table>tbody>tr>td>a.delRow', function (e) {
          e.preventDefault();
          var target = $(this).attr("href");

          $.ajax({
            type: "POST",
            url: target,
            async: false,
            contentType: "application/json; charset=utf-8",
            success: function () {
              updateSMBPathsList();
            }
          })
        });
      </script>
    </li>

      @*-------------------------------------------------------------------------------------------LASER SKIP----------*@
      <li aria-hidden="true">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">
              Configure laser serialization skip logic. When enabled, allows units to bypass laser marking operations under specific conditions (rework, pre-serialized components, customer-supplied serials).
            </p>
          </div>
        </div>

        <div class="uk-grid mn-t-15">
          @Html.AjaxGrid(Url.Action("GetLaserSkip", "PartNumber", new { id = Model.PartID }))
