    public bool AddActivateScannerArrayList(int PartID, int Row, int Col, string MasterID, string PositionID, int ToIndex)
    {
      //Search PartID and side to add...
      if (PartID > 0)
      {
        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@PartID",SqlDbType.Int){Value =PartID},
          new SqlParameter("@MasterID",SqlDbType.NVarChar){Value =(MasterID ?? "").ToString()},
          new SqlParameter("@PositionID",SqlDbType.NVarChar){Value =(PositionID ?? "").ToString()},
          new SqlParameter("@ToIndex",SqlDbType.Int){Value =ToIndex},
          new SqlParameter("@Row",SqlDbType.Int){Value =Row},
          new SqlParameter("@Col",SqlDbType.Int){Value =Col},
        };

        var result = Firstronic.Framework.Queries.InsertQuery($@"INSERT INTO [dbo].[Part_Operation_Serialization_Array_Index]
                   (PartID,
					MasterID,
					PositionID,
					ToIndex,
					Row,
					Col)
					VALUES
                   (@PartID,
					@MasterID,
					@PositionID,
					@ToIndex,
					@Row,
					@Col)", parameters);

        if (result > 0)
        {
          this.NotifySuccess("Successfully saved.");
        }
        else if (result == 0)
        {
          this.NotifyError("Record can not save!");
        }
        else
        {
          this.NotifyError("Error in database.");
        }
      }

      return true;
    }

