public JsonResult SaveActivateScannerArraySize(int PartID, int Rows, int Cols)
{
  try
  {
    if (PartID > 0 && Rows > 0 && Cols > 0)
    {
      // First, check if record exists
      SqlParameter[] checkParams = new SqlParameter[]{
        new SqlParameter("@PartID", SqlDbType.Int){Value = PartID}
      };

      var existingRecord = db.Database.SqlQuery<int>($@"SELECT COUNT(*) FROM [dbo].[Part_Operation_Serialization_Array_Size] WHERE PartID = @PartID", checkParams).FirstOrDefault();

      if (existingRecord > 0)
      {
        // Update existing record
        SqlParameter[] updateParams = new SqlParameter[]{
          new SqlParameter("@PartID", SqlDbType.Int){Value = PartID},
          new SqlParameter("@Rows", SqlDbType.Int){Value = Rows},
          new SqlParameter("@Cols", SqlDbType.Int){Value = Cols}
        };

        var result = db.ExecuteCommand($@"UPDATE [dbo].[Part_Operation_Serialization_Array_Size]
                                         SET Rows = @Rows, Cols = @Cols
                                         WHERE PartID = @PartID", updateParams);

        if (result > 0)
        {
          return Json(new { success = true, message = "Grid size updated successfully." }, JsonRequestBehavior.AllowGet);
        }
      }
      else
      {
        // Insert new record
        SqlParameter[] insertParams = new SqlParameter[]{
          new SqlParameter("@PartID", SqlDbType.Int){Value = PartID},
          new SqlParameter("@Rows", SqlDbType.Int){Value = Rows},
          new SqlParameter("@Cols", SqlDbType.Int){Value = Cols}
        };

        var result = Firstronic.Framework.Queries.InsertQuery($@"INSERT INTO [dbo].[Part_Operation_Serialization_Array_Size]
                   (PartID, Rows, Cols)
                   VALUES
                   (@PartID, @Rows, @Cols)", insertParams);

        if (result > 0)
        {
          return Json(new { success = true, message = "Grid size saved successfully." }, JsonRequestBehavior.AllowGet);
        }
      }
    }

    return Json(new { success = false, message = "Invalid parameters." }, JsonRequestBehavior.AllowGet);
  }
  catch (Exception ex)
  {
    return Json(new { success = false, message = "Error: " + ex.Message }, JsonRequestBehavior.AllowGet);
  }
}

