    public ActionResult CreateSvnProject(int id)
    {
      SqlParameter[] parameters = new SqlParameter[]{
        new SqlParameter("@Id",SqlDbType.Int){Value = id},
      };

      var model0 = Framework.Functions.Utilies.ConvertTo<tbl_CS_idt_partnumbers>(Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT *  FROM CS_idt_partnumbers left join PART_CRITICAL ON CS_idt_partnumbers.PartID = PART_CRITICAL.PartID WHERE CS_idt_partnumbers.PartID=@Id ", parameters)).FirstOrDefault();

      if (model0.PartID > 0)
      {
        string command = $"/usr/local/bin/crear_svn_proyecto.sh {model0.PartNumber}";
        string result = _sshService.RunSshCommand(command);

        return Content(result);  // Show the result of the SSH command execution
      }

      return RedirectToAction("Index");
    }

