      var Layers_Allow_Duplicate_List = new List<SelectListItem>();
      Layers_Allow_Duplicate_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      var model = new tbl_CS_idt_partnumbers_FULL
      {
        IsActive_List = IsActive_List,
        IsCritical_List = IsCritical_List,
        HavePVS_List = HavePVS_List,
        IsSerializationByPanel_List = IsSerializationByPanel_List,
        IsSerializationByPanelAuto_List = IsSerializationByPanelAuto_List,
