        PiecesByPanel = model0.PiecesByPanel,
        PartSerialPanelFormat = model0.PartSerialPanelFormat,
        HavePVS = model0.HavePVS,
        Part_key = model0.Part_key,
        IsSerializationByPanel = model0.IsSerializationByPanel,
        IsSerializationByPanelAuto = model0.IsSerializationByPanelAuto,
        RowLabel = model0.RowLabel,
        BoxSize = model0.BoxSize,
        Layers = model0.Layers,
        PackType = model0.PackType,
        APlacements = model0.APlacements,
        BPlacements = model0.BPlacements,
        PartSerialFormatEasy = model0.PartSerialFormatEasy,
        PartSerialPanelFormatEasy = model0.PartSerialPanelFormatEasy,
        Facility_Key = model0.Facility_Key,
        FacilityList = FirstronicFacilitiesList,
        IsLaser_List = IsLaser_List,
        LabelByPanel_List = LabelByPanel_List,
        IsOOBA_List = IsOOBA_List,

        PackTypeRowSize = model0.PackTypeRowSize,
        Part_Type_ID = model0.Part_Type_ID,
        PackRowSize = model0.PackRowSize,
        Layers_Allow_Duplicate_List = Layers_Allow_Duplicate_List,
        Cost = model0.Cost
      };

      //Read if is laser...
      SqlParameter[] idParameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.Int){Value = model.PartID},
      };
      int LabelByPanelVerify = Firstronic.Framework.Queries.GetIntFromQuery("SELECT TOP (1000) [AutoID]FROM [CS_tbl_partnumber_ser_bypanel]WHERE PartID=@Id", idParameters);

      if (LabelByPanelVerify > 0)
      {
        model.LabelByPanel = true;
      }
      else
      {
        model.LabelByPanel = false;
      }

      DataTable IsOOBAVerify = Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT TOP (1)  * FROM [SP_tbl_layers_extra]WHERE PartID=@Id order by AutoID Desc", idParameters);

      if (IsOOBAVerify.Rows.Count > 0)
      {
        model.IsOOBA = true;


        foreach (DataRow row in IsOOBAVerify.Rows)
        {
          model.LayerCode = row["LayerCode"].ToString();
          model.LayersInicio = Convert.ToInt32(row["LayersInicio"]);
          model.LayersFinal = Convert.ToInt32(row["LayersFinal"]);
          model.LayersIniciotype = Convert.ToInt32(row["LayersIniciotype"]);
          model.LayersFinalType = Convert.ToInt32(row["LayersFinalType"]);
        }
      }
      else
      {
        model.IsOOBA = false;
      }



      model.Fense = Firstronic.Framework.Queries.GetIntFromQuery("SELECT Time FROM SP_tbl_fance_time_test WHERE partid=@Id", idParameters);



      model.IsLaser = Firstronic.Framework.Queries.GetBooleanFromQuery("SELECT CAST( CASE WHEN EXISTS(SELECT * FROM CS_tbl_partnumber_sertype WHERE PartID=@Id) THEN 1 ELSE 0 END AS BIT) ", idParameters);

      model.LabelsCode = Firstronic.Framework.Queries.GetStringFromQuery("SELECT isnull([LabelCode],'') as LabelCode  FROM [PR_tbl_labelscode_pn]  WHERE PartID=@Id", idParameters);

      model.Packout_Stock_location = Firstronic.Framework.Queries.GetIntFromQuery("SELECT isnull([Location],0) as Location  FROM Part_Operation_Default_Stock_Location WHERE PartID=@Id AND AreaID='14'", idParameters);

      model.NoFilters = Firstronic.Framework.Queries.GetBooleanFromQuery("SELECT CAST( CASE WHEN EXISTS(SELECT [AutoID] FROM [Part_Operation_Packout_No_Filters_Engineering] where partid=@Id UNION SELECT [AutoID] FROM [Part_Operation_Packout_No_Filters] where partid=@Id) THEN 1 ELSE 0 END AS BIT)", idParameters);

      model.validatescrews = Firstronic.Framework.Queries.GetBooleanFromQuery("SELECT CAST( CASE WHEN EXISTS(SELECT [AutoID] FROM [Part_Operation_Packout_Tester_Screws] where partid=@Id) THEN 1 ELSE 0 END AS BIT)", idParameters);

      model.validateKeyence = Firstronic.Framework.Queries.GetBooleanFromQuery("SELECT CAST( CASE WHEN EXISTS(SELECT [AutoID] FROM [Part_Operation_Packout_Scanner_Small] where partid=@Id) THEN 1 ELSE 0 END AS BIT)", idParameters);

      model.AllowMixPackout = Firstronic.Framework.Queries.GetBooleanFromQuery("SELECT CAST( CASE WHEN EXISTS(SELECT [AutoID] FROM [PART_OPERATION_PACKOUT_ALLOW_MIX] where partid=@Id) THEN 1 ELSE 0 END AS BIT)", idParameters);

      return View(model);
    }

