    public ActionResult SendEmailPanelEdit(string status, int partid, int areaID)
    {
      try
      {
        SqlParameter[] idParameters = new SqlParameter[]{
          new SqlParameter("@AreaID",SqlDbType.Int){Value = areaID},
          new SqlParameter("@PartID",SqlDbType.Int){Value = partid}
        };

        // LIST
        DataTable da_getlistmail = Firstronic.Framework.Functions.Queries.GetDatatableFromQuery(@"SELECT HR_idt_users.Email FROM IT_Emails_Suscriptions INNER JOIN HR_idt_users ON IT_Emails_Suscriptions.ControlID = HR_idt_users.ControlID WHERE (IT_Emails_Suscriptions.ReporteID = '60') ORDER BY IT_Emails_Suscriptions.ControlID");

        string distribution_list = "";

        foreach (DataRow row in da_getlistmail.Rows)
        {
          distribution_list = distribution_list + row["Email"].ToString() + ",";
        }

        distribution_list = distribution_list.Remove(distribution_list.Length - 1);

        string PartNumber = Firstronic.Framework.Queries.GetIntFromQuery("SELECT [PartNumber] FROM [CS_idt_partnumbers] where PartID=@PartID", idParameters).ToString();

        string area = Firstronic.Framework.Queries.GetIntFromQuery("SELECT Area FROM [PD_idt_areas] where AreaID=@AreaID", idParameters).ToString();

        SqlParameter[] NameParameter = new SqlParameter[]{
          new SqlParameter("@UserID",SqlDbType.NVarChar){Value = User.Identity.GetUserName()}
        };

        string UserName = Firstronic.Framework.Queries.GetIntFromQuery("SELECT CONCAT(LastName, ' ', FirstName) FROM HR_idt_users where User_ID =@UserID order by Add_User desc", NameParameter).ToString();


        MailMessage email = new MailMessage();
        SmtpClient smtp = new SmtpClient();
        string emailadmin = Firstronic.Framework.GlobalVariables.GlobalVariables.SMTPEmail;
        string emailpassword = Firstronic.Framework.GlobalVariables.GlobalVariables.SMTPPassword;

        email.From = new MailAddress(emailadmin, "ManagePartNumber");
        email.Subject = "Part Number " + PartNumber + "    " + status + " In Area " + area + "  ";//( " + DateTime.Now.ToString("dd / MMM / yyy HH:mm:ss") + " )
        email.SubjectEncoding = System.Text.Encoding.UTF8;
        string mensaje = "The next Part Number  " + PartNumber + "" + status + " In Area " + area + " By  " + UserName + "</br>" + link;
        email.Body = mensaje + "<br/><hr><br/>This is an automatically generated email – please do not reply to it. If you have any queries please email emarquez@firstronic.com.";
        email.IsBodyHtml = true;
        email.Priority = MailPriority.Normal;
        string SMTPServer = Firstronic.Framework.Functions.Queries.GetIntFromQuerystring("SELECT Result FROM [dbo].[CF_idt_defaults] where Description='SMTPServer'");
        smtp.Host = SMTPServer;
        string SMTPPort = Firstronic.Framework.Functions.Queries.GetIntFromQuerystring("SELECT Result FROM [dbo].[CF_idt_defaults] where Description='SMTPPort'");
        smtp.Port = Int32.Parse(SMTPPort);
        smtp.Timeout = 10000;
        string SMTPSSL = Firstronic.Framework.Functions.Queries.GetIntFromQuerystring("SELECT Result FROM [dbo].[CF_idt_defaults] where Description='SMTPSSL'");
        if (SMTPSSL == "1")
        {
          smtp.EnableSsl = true;
        }

        else
        {
          smtp.EnableSsl = false;
        }
        smtp.UseDefaultCredentials = false;
        smtp.Credentials = new NetworkCredential(emailadmin, emailpassword);
        email.To.Add(distribution_list);
        smtp.Send(email);
        email.Dispose();
        return Json("");
      }
      catch (Exception ex)
      {
        ViewBag.Message = "ERROR:" + ex.Message.ToString();
        return Json("");
      }

    }

