      };


      var model = new tbl_Part_Operation_Review_Operation_FULL_partial();

      model.id = id;

      DataTable dtid = Firstronic.Framework.Queries.GetDatatableFromQuery($@"SELECT  isnull(Part_Operation_Review_Operation.AutoID,0) as AutoID, Part_Operation_Review_Operation.PartID, Part_Operation_Review_Operation.CurrentAreaID, Part_Operation_Review_Operation.PreviousAreaID, Part_Operation_Review_Operation.Facility_Key, PD_idt_areas.Area, PD_idt_areas_1.Area AS AreaToCheck,isnull(Part_Operation_Review_Operation.Previous_Date,'') as Previous_Date,isnull(Part_Operation_Review_Operation_Validate.LimitDate,DATEADD(DAY,+7,GETDATE())) as LimitDate,case when Part_Operation_Review_Operation_Validate.TrnDate is not null then LEFT(CONVERT(VARCHAR,Part_Operation_Review_Operation_Validate.TrnDate, 120), 10) else 'Not' end AS Approved, Part_Operation_Review_Operation.LimitDate_Deviation, Part_Operation_Review_Operation.CurrentSide, Part_Operation_Review_Operation.PreviousSide,Part_Operation_Review_Operation.DaysFromFirstRecord,Part_Operation_Review_Operation.DaysFromLastRecord FROM Part_Operation_Review_Operation INNER JOIN PD_idt_areas ON Part_Operation_Review_Operation.CurrentAreaID = PD_idt_areas.AreaID LEFT JOIN PD_idt_areas AS PD_idt_areas_1 ON Part_Operation_Review_Operation.PreviousAreaID = PD_idt_areas_1.AreaID FULL JOIN Part_Operation_Review_Operation_Validate ON Part_Operation_Review_Operation.PartID = Part_Operation_Review_Operation_Validate.PartID AND Part_Operation_Review_Operation.CurrentAreaID = Part_Operation_Review_Operation_Validate.CurrentAreaID AND Part_Operation_Review_Operation.CurrentSide = Part_Operation_Review_Operation_Validate.CurrentSide AND Part_Operation_Review_Operation.PreviousAreaID = Part_Operation_Review_Operation_Validate.PreviousAreaID AND Part_Operation_Review_Operation.PreviousSide = Part_Operation_Review_Operation_Validate.PreviousSide WHERE Part_Operation_Review_Operation.PartID =" + id + " or Part_Operation_Review_Operation_Validate.PartID =@Id", idParameters);

      var resultado = Firstronic.Framework.Queries.ExecuteSimpleQuery($@"DELETE FROM Part_Operation_Review_Operation WHERE AutoID=@Id", idParameters);

      if (dtid.Rows.Count > 0)
      {
        int partid = (int)dtid.Rows[0]["PartID"];

        if (partid > 0)
        {
          SqlParameter[] sqlParameters = new SqlParameter[]{
            new SqlParameter("@PartID",SqlDbType.Int){Value = partid}
          };

          int CustomerID = Firstronic.Framework.Queries.GetIntFromQuery("SELECT [CustomerID] FROM  [CS_idt_partnumbers] WHERE PartID=@PartID", sqlParameters);

          if (CustomerID > 0)
          {
            int PositionID = 4;

            SqlParameter[] CustomerIDParameters = new SqlParameter[]{
              new SqlParameter("@CustomerID",SqlDbType.Int){Value = CustomerID},
