    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    [Authorize(Roles = "BF Administrator,BF Part Edit,BF Rates Edit")]
    public bool AddRates(int AreaID, int PartID, int StationID, int Quantity, string side)
    {

      SqlParameter[] stationParameters = new SqlParameter[]{
          new SqlParameter("@StationID",SqlDbType.Int){Value = StationID},
      };

      SqlParameter[] areaParameters = new SqlParameter[]{
          new SqlParameter("@AreaID",SqlDbType.Int){Value = AreaID},
      };

      DataTable dt_stations = Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT[StationID] FROM [PD_idt_stations] where StationID=@StationID", stationParameters);
      if (StationID == -1 && AreaID == 1)
      {
        //NOSE PUEDE AGREGAR
        this.NotifyError("cCannot  Select all .");
      }
      else
      {
        if (StationID == -1)
        {
          dt_stations = Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT [StationID] FROM [PD_idt_stations] where AreaID=@AreaID", areaParameters);
        }

        foreach (DataRow row_station in dt_stations.Rows)
        {

          string stationids = row_station[0].ToString();

          //Search area and side to add...
          double factor = 1;
          double rate = 1;

          //buscamos la eficiencia 
          var resultefficency = Firstronic.Framework.Queries.GetIntFromQuery("SELECT Efficence FROM EN_tbl_efficency_stations WHERE stationid=@StationID", stationParameters);
          if (resultefficency > 0)
          {
            factor = resultefficency / (double)100;
            rate = factor * Quantity;
          }
          else
          {
            factor = 100 / (double)100;
            rate = factor * Quantity;
          }

          //verificamos si existe el rate en  la tabla PD_tbl_stations_rates
          SqlParameter[] NameParameter = new SqlParameter[]{
          new SqlParameter("@UserID",SqlDbType.NVarChar){Value = User.Identity.GetUserName()}
          };

          var controlid = Firstronic.Framework.Queries.GetIntFromQuery("select ControlID from HR_idt_users where User_ID=@UserID", NameParameter);

          SqlParameter[] rateParameters = new SqlParameter[]{
            new SqlParameter("@AreaID",SqlDbType.Int){Value = AreaID},
            new SqlParameter("@PartID",SqlDbType.Int){Value = PartID},
            new SqlParameter("@stationid",SqlDbType.Int){Value = stationids},
            new SqlParameter("@side",SqlDbType.VarChar){Value = side},
            new SqlParameter("@rate",SqlDbType.Int){Value = rate}, //RATE
            new SqlParameter("@Quantity",SqlDbType.Int){Value = Quantity} //ORIGINAL
          };

          var resultifexistrate = Firstronic.Framework.Queries.GetIntFromQuery("SELECT ID FROM PD_tbl_stations_rates WHERE partid=@PartID and areaid=@AreaID and stationid=@stationid and side=@side", rateParameters);

          if (resultifexistrate > 0)
          {
            //actualizamos rates
            var updaterates = Firstronic.Framework.Queries.GetIntFromQuery("UPDATE PD_tbl_stations_rates SET Rate=@rate WHERE partid=@PartID and areaid=@AreaID and stationid=@stationid and side=@side", rateParameters);

          }
          else
          {
            var insertrates = Firstronic.Framework.Queries.GetIntFromQuery("INSERT INTO PD_tbl_stations_rates (PartID,AreaID,StationID,Side,Rate) VALUES (@PartID,@AreaID,@stationid,@side,@rate)", rateParameters);

          }

          //verificamos si exist en PD_tbl_stations_rates100
          var resultifexistrate100 = Firstronic.Framework.Queries.GetIntFromQuery("SELECT AutoID FROM PD_tbl_stations_rates100 WHERE partid=@PartID and areaid=@AreaID and stationid=@stationid and side=@side", rateParameters);
          if (resultifexistrate100 > 0)
          {
            var updaterates = Firstronic.Framework.Queries.GetIntFromQuery("UPDATE PD_tbl_stations_rates100 SET Rate=@Quantity WHERE partid=@PartID and areaid=@AreaID and stationid=@stationid and side=@side", rateParameters);
          }
          else
          {
            var insertrates = Firstronic.Framework.Queries.GetIntFromQuery("INSERT INTO PD_tbl_stations_rates100 (PartID,AreaID,StationID,Side,Rate) VALUES (@PartID,@AreaID,@stationid,@side,@Quantity)", rateParameters);
          }

        }


      }
      return true;
    }


