    [AcceptVerbs(HttpVerbs.Post)]
    [Authorize(Roles = "BF Administrator,BF Part Edit")]
    public JsonResult AddSMBPath(int PartID, int AreaID, string Side,
                                  string SMB_PATH, string SMB_FILE_PATTERN,
                                  int SMB_READ_INTERVAL, bool SMB_ENABLED, string SMB_TYPE,
                                  string SMB_DOMAIN, string SMB_USERNAME, string SMB_PASSWORD)
    {
      try
      {
        // Get Part_Key for the PartID
        string partKeyQuery = "SELECT TOP 1 Part_Key FROM CS_idt_partnumbers WHERE PartID = @PartID";
        SqlParameter[] partKeyParams = new SqlParameter[]{
          new SqlParameter("@PartID", SqlDbType.Int){ Value = PartID }
        };

        var partKey = db.Database.SqlQuery<int>(partKeyQuery, partKeyParams).FirstOrDefault();

        if (partKey == 0)
        {
          this.NotifyError("Part not found");
          return Json(new { success = false, message = "Part not found" });
        }

        // Check for duplicates
        string checkQuery = @"
          SELECT COUNT(*)
          FROM PART_OPERATION_AREAS_SMB
          WHERE PartID = @PartID AND AreaID = @AreaID AND Side = @Side";

        SqlParameter[] checkParams = new SqlParameter[]{
          new SqlParameter("@PartID", SqlDbType.Int){ Value = PartID },
          new SqlParameter("@AreaID", SqlDbType.Int){ Value = AreaID },
          new SqlParameter("@Side", SqlDbType.NVarChar){ Value = Side }
        };

        var exists = db.Database.SqlQuery<int>(checkQuery, checkParams).FirstOrDefault();

        if (exists > 0)
        {
          this.NotifyError("Configuration already exists for this Area and Side");
          return Json(new { success = false, message = "Configuration already exists for this Area and Side" });
        }

        // Encrypt password if provided
        byte[] encryptedPassword = null;
        if (!string.IsNullOrWhiteSpace(SMB_PASSWORD))
        {
          encryptedPassword = System.Text.Encoding.UTF8.GetBytes(SMB_PASSWORD);
          // TODO: Implement proper encryption using System.Security.Cryptography
          // For now, storing as UTF8 bytes - should use AES or similar encryption
        }

        // Insert configuration
        string insertQuery = @"
          INSERT INTO PART_OPERATION_AREAS_SMB
          (PartID, AreaID, Side, Part_Key, SMB_PATH, SMB_FILE_PATTERN,
           SMB_READ_INTERVAL, SMB_ENABLED, SMB_TYPE, SMB_DOMAIN, SMB_USERNAME, SMB_PASSWORD_ENCRYPTED,
           CreatedDate, CreatedBy)
          VALUES
          (@PartID, @AreaID, @Side, @Part_Key, @SMB_PATH, @SMB_FILE_PATTERN,
           @SMB_READ_INTERVAL, @SMB_ENABLED, @SMB_TYPE, @SMB_DOMAIN, @SMB_USERNAME, @SMB_PASSWORD_ENCRYPTED,
           GETDATE(), @CreatedBy)";

        SqlParameter[] insertParams = new SqlParameter[]{
          new SqlParameter("@PartID", SqlDbType.Int){ Value = PartID },
          new SqlParameter("@AreaID", SqlDbType.Int){ Value = AreaID },
          new SqlParameter("@Side", SqlDbType.NVarChar){ Value = Side },
          new SqlParameter("@Part_Key", SqlDbType.Int){ Value = partKey },
          new SqlParameter("@SMB_PATH", SqlDbType.NVarChar){ Value = SMB_PATH },
          new SqlParameter("@SMB_FILE_PATTERN", SqlDbType.NVarChar){ Value = SMB_FILE_PATTERN ?? "*.TXT" },
          new SqlParameter("@SMB_READ_INTERVAL", SqlDbType.Int){ Value = SMB_READ_INTERVAL },
          new SqlParameter("@SMB_ENABLED", SqlDbType.Bit){ Value = SMB_ENABLED },
          new SqlParameter("@SMB_TYPE", SqlDbType.VarChar){ Value = string.IsNullOrWhiteSpace(SMB_TYPE) ? (object)DBNull.Value : SMB_TYPE },
          new SqlParameter("@SMB_DOMAIN", SqlDbType.NVarChar){ Value = string.IsNullOrWhiteSpace(SMB_DOMAIN) ? (object)DBNull.Value : SMB_DOMAIN },
          new SqlParameter("@SMB_USERNAME", SqlDbType.NVarChar){ Value = string.IsNullOrWhiteSpace(SMB_USERNAME) ? (object)DBNull.Value : SMB_USERNAME },
          new SqlParameter("@SMB_PASSWORD_ENCRYPTED", SqlDbType.VarBinary){ Value = encryptedPassword ?? (object)DBNull.Value },
          new SqlParameter("@CreatedBy", SqlDbType.NVarChar){ Value = User.Identity.Name }
        };

        db.Database.ExecuteSqlCommand(insertQuery, insertParams);

        this.NotifySuccess("SMB path configuration added successfully");
        return Json(new { success = true });
      }
      catch (Exception ex)
      {
        this.NotifyError("Error adding SMB path: " + ex.Message);
        return Json(new { success = false, message = ex.Message });
      }
    }

