    [AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
    [Authorize(Roles = "BF Administrator,BF Part Edit")]
    public bool AddBOM(int PartID)
    {
      //Search area and side to add...
      if (PartID > 0)
      {
        SqlParameter[] partParameters = new SqlParameter[]{
          new SqlParameter("@PartID",SqlDbType.Int){Value = PartID}
        };

        int Part_Key = Firstronic.Framework.Queries.GetIntFromQuery("SELECT [Part_key] FROM [CS_idt_partnumbers] WHERE PartID=@PartID", partParameters);

        SqlParameter[] partKeyParameters = new SqlParameter[]{
          new SqlParameter("@Part_Key",SqlDbType.Int){Value = Part_Key}
        };

        //queryvalidted unable to skip openquery parametrization. 
        string queryvalidated = "select * from OPENQUERY(PLEX,'SELECT p.Part_No as PartNo,BOM.Note as Note,BOM.Component_Part_key,BOM.BOM_Key,BOM.Part_Operation_Key,BOM.Quantity FROM (SELECT Component_Part_key,Part_Operation_Key,Note,BOM_Key,Quantity From [part_v_BOM]  Where Part_Key =''" + Part_Key + "'' ) BOM INNER JOIN [part_v_Part] p ON BOM.Component_Part_key = p.Part_Key')";

        DataTable dt2 = Firstronic.Framework.Functions.Queries.GetDatatableFromQuery(queryvalidated);

        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"UPDATE [dbo].[PLEX_Part_v_BOM] SET Flag='1' WHERE Part_Key=@Part_Key", partKeyParameters);
        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"UPDATE [dbo].[Part_BOM] SET Flag='1' WHERE Part_Key=@Part_Key", partKeyParameters);
        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"DELETE FROM [dbo].[PLEX_Part_v_BOM] WHERE Flag='1'", partKeyParameters);
        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"DELETE FROM [dbo].[Part_BOM] WHERE Flag='1'", partKeyParameters);


        int Facility_Key = Firstronic.Framework.Functions.Queries.GetIntFromQuery("SELECT [Facility_Key] FROM [COMMON_FACILITIES] WHERE [Main_Facility]=1");

        foreach (DataRow fila2 in dt2.Rows)
        {
          SqlParameter[] timeParameters = new SqlParameter[]{
              new SqlParameter("@BOM_Key",SqlDbType.Int) {Value = fila2["BOM_Key"].ToString()},
              new SqlParameter("@Part_Key",SqlDbType.Int){Value = Part_Key},
              new SqlParameter("@Part_Operation_Key",SqlDbType.Int){Value = fila2["Part_Operation_Key"].ToString()},
              new SqlParameter("@Component_Part_Key",SqlDbType.Int){Value = fila2["Component_Part_Key"].ToString()},
              new SqlParameter("@Note",SqlDbType.NVarChar){Value = fila2["Note"].ToString()},
              new SqlParameter("@Quantity",SqlDbType.Float){Value = fila2["Quantity"].ToString()},
              new SqlParameter("@Facility_Key",SqlDbType.Int){Value = Facility_Key}
            };

          Firstronic.Framework.Queries.ExecuteSimpleQuery(@"INSERT INTO [dbo].[PLEX_Part_v_BOM] ([BOM_Key] ,[Part_Key] ,[Part_Operation_Key] ,[Component_Part_Key],[Note],Quantity) VALUES (@BOM_Key,@Part_Key,@Part_Operation_Key,@Component_Part_Key,@Note,@Quantity)", timeParameters);

          Firstronic.Framework.Queries.ExecuteSimpleQuery(@"INSERT INTO [dbo].[Part_BOM] ([BOM_Key] ,[Part_Key] ,[Part_Operation_Key] ,[Component_Part_Key],[Note],Quantity,Facility_Key) VALUES (@BOM_Key,@Part_Key,@Part_Operation_Key,@Component_Part_Key,@Note,@Quantity,@Facility_Key)", timeParameters);
        }

        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"UPDATE [dbo].[RW_tbl_bom] SET Flag='1' WHERE PartID=@PartID", partParameters);
        Firstronic.Framework.Queries.ExecuteSimpleQuery(@"DELETE FROM [dbo].[RW_tbl_bom] WHERE Flag='1'", partKeyParameters);

        foreach (DataRow fila2 in dt2.Rows)
        {
          string MyString = fila2["Note"].ToString().Replace(" ", "");
          string[] MyArray = MyString.Split(',');
          List<string> MyList = new List<string>(MyArray);

          foreach (string item in MyList)
          {
            if (string.IsNullOrEmpty(item))
            {
              SqlParameter[] Parameterstbl_bom = new SqlParameter[]
                  {
                    new SqlParameter("@PartID",SqlDbType.Int){Value = PartID},
                    new SqlParameter("@Location",SqlDbType.NVarChar){Value = item},
                  };

              Firstronic.Framework.Queries.ExecuteSimpleQuery($"INSERT INTO [dbo].[RW_tbl_bom] ([PartID] ,[ComponentID] ,[Location] ,[Flag]) VALUES (@PartID,@Location,'N/A','0')", Parameterstbl_bom);
            }
            else
            {
              if (item.Substring(0, 1) == "(" && item.Substring(item.Length - 1, 1) == ")")
              {
                string sinparentesis = item.Substring(1, item.Length - 2);
                string[] MyArray2 = sinparentesis.Split('-');
                List<string> MyList2 = new List<string>(MyArray2);

                // Encontrar inicio
                int esnumero1 = MyList2[0].TakeWhile(c => !char.IsDigit(c)).Count();
                int inicio = int.Parse(MyList2[0].Substring(esnumero1));

                // Encontrar fin
                int esnumero2 = MyList2[1].TakeWhile(c => !char.IsDigit(c)).Count();
                string loc = MyList2[1].Substring(0, MyList2[1].Length - esnumero2 - 1);
                int fin = int.Parse(MyList2[1].Substring(esnumero2));

                for (int j = inicio; j <= fin; j++)
                {
                  SqlParameter[] Parameters = new SqlParameter[]
                  {
                    new SqlParameter("@PartID",SqlDbType.Int){Value = PartID},
                    new SqlParameter("@PartNo",SqlDbType.NVarChar){Value = fila2["PartNo"]},
                    new SqlParameter("@Location",SqlDbType.NVarChar){Value = loc[j].ToString()},
                  };

                  Firstronic.Framework.Queries.ExecuteSimpleQuery($"INSERT INTO [dbo].[RW_tbl_bom] ([PartID] ,[ComponentID] ,[Location] ,[Flag]) VALUES (@PartID,@PartNo,@Location,'0')", Parameters);
                }
              }
              else
              {

                SqlParameter[] Parameters = new SqlParameter[]
                  {
                    new SqlParameter("@PartID",SqlDbType.Int){Value = PartID},
                    new SqlParameter("@PartNo",SqlDbType.NVarChar){Value = fila2["PartNo"]},
                    new SqlParameter("@Location",SqlDbType.NVarChar){Value = item},
                  };

                Firstronic.Framework.Queries.ExecuteSimpleQuery($"INSERT INTO [dbo].[RW_tbl_bom] ([PartID] ,[ComponentID] ,[Location] ,[Flag]) VALUES (@PartID,@PartNo,@Location,'0')", Parameters);
              }
            }
          }
        }
      }
      return true;
    }

