              if (newid == 0)
              {
                //Calulate cost area.
                double operationCost = Firstronic.Framework.Queries.GetDoubleFromQuery(@"SELECT isnull(SUM([Quantity]*isnull([Part_Cost].Cost,0)),0) as Cost FROM [dbo].[Part_BOM] LEFT JOIN[dbo].[Part_Cost] ON [Part_BOM].Component_Part_Key =[Part_Cost].Part_Key AND[Part_Cost].Cost_Model_ID = 5058 where Part_Operation_Key = @Part_Op_Key", parameterstage);

                cost += operationCost;

                SqlParameter[] parameterstage2 = new SqlParameter[]
              {
                new SqlParameter("@PartID",SqlDbType.Int){Value = vpartid},
                new SqlParameter("@Current",SqlDbType.Int){Value = current},
                new SqlParameter("@AreaID",SqlDbType.Int){Value = dtStage.Rows[0]["AreaID"].ToString()},
