                Firstronic.Framework.Queries.ExecuteSimpleQuery(@"INSERT INTO PD_tbl_rutes ([PartID] ,[Stage] ,[AreaID] ,[Side],Part_Operation_Key,Cost) VALUES (@PartID,@Current,@AreaID,@Side,@Part_Op_Key,@Cost)", parameterstage2);
                if (rowOperation["Standard"].ToString() == "1")
                {
                  current += 1;
                }
              }

            }
            else
            {


            }
          }
        }

        SqlParameter[] timeParameters = new SqlParameter[]{
              new SqlParameter("@Part_Key",SqlDbType.Int) {Value = Part_Key}
            };

        Firstronic.Framework.Queries.ExecuteSimpleQuery("DELETE FROM Part_Operation_Routing WHERE Part_Key=@Part_Key", timeParameters);

        int Facility_Key = Firstronic.Framework.Functions.Queries.GetIntFromQuery("SELECT [Facility_Key] FROM [COMMON_FACILITIES] WHERE [Main_Facility]=1");

        Firstronic.Framework.Functions.Queries.ExecuteSimpleQuery("INSERT INTO [dbo].[Part_Operation_Routing] ([Facility_Key],[Part_Operation_Key] ,[Operation_No] ,[Operation_Key] ,[Part_Key] ,[Part_Op_Type_Key]) SELECT * FROM OPENQUERY(PLEX, 'SELECT Part_v_Part_Operation.Plexus_customer_no,Part_v_Part_Operation.[Part_Operation_Key],Part_v_Part_Operation.[Operation_No],Part_v_Part_Operation.[Operation_Key],Part_v_Part_Operation.[Part_Key],Part_v_Part_Operation.[Part_Op_Type_Key] FROM Part_v_Part_Operation LEFT JOIN Part_v_Operation ON Part_v_Part_Operation.Operation_Key=Part_v_Operation.Operation_Key WHERE Part_Key=''" + Part_Key + "''')");

        Firstronic.Framework.Functions.Queries.ExecuteSimpleQuery("DELETE FROM PD_tbl_rutes WHERE Flag='1'");

        DataTable dtAddFilter = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT [AutoID],[PartID],[Stage],[AreaID],[Side],[Flag],[PackoutStage],[Part_Operation_Key],[Facility_Key],[Optional],[NoPlex],[DisableWIP],[Cost]   FROM [PD_tbl_rutes]  where PartID = @PartID order by Stage asc", partParameters);

        int i = 0;

        SqlParameter[] delparameter = new SqlParameter[]
              {
                new SqlParameter("@PartID",SqlDbType.Int){Value = vpartid},

              };

        Firstronic.Framework.Queries.ExecuteSimpleQuery("DELETE FROM Part_Operation_Review_Operation_FULL WHERE PartID=@PartID", delparameter);

        foreach (DataRow rowFilter in dtAddFilter.Rows)
        {
          int stage = int.Parse(dtAddFilter.Rows[i]["Stage"].ToString());
          if (stage > 1)
          {
            if (stage >= 3)
            {
              for (int ii = 1; ii < stage; ii++)
              {
                SqlParameter[] Parameters = new SqlParameter[]
                {
                  new SqlParameter("@PartID",SqlDbType.Int){Value = vpartid},
                  new SqlParameter("@AreaID",SqlDbType.Int){Value = int.Parse(dtAddFilter.Rows[i]["AreaID"].ToString())},
                  new SqlParameter("@PreviousAreaID",SqlDbType.Int){Value = int.Parse(dtAddFilter.Rows[ii - 1]["AreaID"].ToString())},
                  new SqlParameter("@Side",SqlDbType.NVarChar){Value = dtAddFilter.Rows[i]["Side"].ToString()},
                  new SqlParameter("@PreviousSide",SqlDbType.NVarChar){Value = dtAddFilter.Rows[ii - 1]["Side"].ToString()},
                };

                Firstronic.Framework.Queries.ExecuteSimpleQuery(@"INSERT INTO [dbo].[Part_Operation_Review_Operation_FULL]([PartID],[CurrentAreaID],[PreviousAreaID],[Facility_Key],[Previous_Date],[WrtDate],[LimitDate_Deviation],[CurrentSide],[PreviousSide],[DaysFromFirstRecord])VALUES (@PartID,@AreaID,@PreviousAreaID,NULL,DATEADD(year, -3, GETDATE()),GETDATE(),DATEADD(year, +3, GETDATE()),@Side,@PreviousSide,730)", Parameters);

              }
            }
            else
            {
              SqlParameter[] Parameters = new SqlParameter[]
                {
                  new SqlParameter("@PartID",SqlDbType.Int){Value = vpartid},
                  new SqlParameter("@AreaID",SqlDbType.Int){Value = int.Parse(dtAddFilter.Rows[i]["AreaID"].ToString())},
                  new SqlParameter("@PreviousAreaID",SqlDbType.Int){Value = int.Parse(dtAddFilter.Rows[i - 1]["AreaID"].ToString())},
                  new SqlParameter("@Side",SqlDbType.NVarChar){Value = dtAddFilter.Rows[i]["Side"].ToString()},
                  new SqlParameter("@PreviousSide",SqlDbType.NVarChar){Value = dtAddFilter.Rows[i - 1]["Side"].ToString()},
                };

              Firstronic.Framework.Queries.ExecuteSimpleQuery(@"INSERT INTO [dbo].[Part_Operation_Review_Operation_FULL]([PartID],[CurrentAreaID],[PreviousAreaID],[Facility_Key],[Previous_Date],[WrtDate],[LimitDate_Deviation],[CurrentSide],[PreviousSide],[DaysFromFirstRecord])VALUES (@PartID,@AreaID,@PreviousAreaID,NULL,DATEADD(year, -3, GETDATE()),GETDATE(),DATEADD(year, +3, GETDATE()),@Side,@PreviousSide,730)", Parameters);
            }
          }
          i++;
        }
      }
      return true;
    }


