        };

        int ControlID = Firstronic.Framework.Queries.GetIntFromQuery("SELECT  [ControlID] FROM  [HR_idt_users] where Plexus_User_No=@UserID", ControlParameters); //;

        int AprovedBy = ControlID;

        //2024-04-23 EM: If is doc general (2) disable previous similar title
        if (DocType == 2)
        {
          Firstronic.Framework.Queries.ExecuteSimpleQuery("UPDATE EN_tbl_visualAids SET Active=0 Where PartID=@PartID and ProcessID=@ProcessID and DocType=@DocType and Title=@Title", parameterVersions);
        }

        Uri uri = Request.Url;
        var scheme = uri.Scheme; // returns http, https
        var scheme2 = uri.Scheme + Uri.SchemeDelimiter; // returns http://, https://
        var host = uri.Host; // return www.mywebsite.com
