        if (UrlWeb.Length > 4)
        {
          urlLink = UrlWeb;
        }

        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@DocType",SqlDbType.Int){Value =DocType},
            new SqlParameter("@PartID",SqlDbType.Int){Value =PartID},
            new SqlParameter("@Side",SqlDbType.VarChar){Value =(Side ?? "").ToString()},
            new SqlParameter("@AreaID",SqlDbType.Int){Value =AreaID},
            new SqlParameter("@ProcessID",SqlDbType.Int){Value =ProcessID},
            new SqlParameter("@Url",SqlDbType.VarChar){Value = (urlLink ?? "")},
            new SqlParameter("@Version",SqlDbType.Int){Value =Version},
            new SqlParameter("@Active",SqlDbType.Bit){Value = true},
            new SqlParameter("@ControlID",SqlDbType.Int){Value =ControlID},
            new SqlParameter("@AprovedBy",SqlDbType.Int){Value =AprovedBy},
            new SqlParameter("@Title",SqlDbType.NVarChar){Value =(Title ?? "").ToString()},
            new SqlParameter("@Comments",SqlDbType.VarChar){Value =(Comments ?? "").ToString()}
        };

        int resultado = Firstronic.Framework.Queries.InsertQuery(@"INSERT INTO [dbo].[EN_tbl_visualAids] (
					DocType,PartID,Side,AreaID,ProcessID,Url,Version,TrnUpdate,Active,ControlID,AprovedBy,Comments,Aproved,aprovedvisible,Title)
					VALUES (@DocType,
					@PartID,
					@Side,
					@AreaID,
					@ProcessID,
					@Url,
					@Version,
					GETDATE(),
					1,
	        @ControlID,
					@AprovedBy,
					@Comments,1,1,@Title)", parameters);

        if (resultado > 0)
        {
          return true;
        }
        else
        {
          return false;
        }
      }
      else
      {
